//-------------------------------------------------------------------------
// Row 상태에 대한 체크한 후 진행값 반환 ; 리턴값-->  F = 실행중지, T = 진행가능
//-------------------------------------------------------------------------
scwin.f_rowStateView = async function (row_value) {
  var rowState = ds_CooperationCompanyInputHeavyEquip.getRowStatus(row_value);
  var msg_str = "";
  var return_value = "T";
  var msg_str_tail = "\n 단축번호를 입력하실 수 없습니다.";
  if (rowState == "R") {
    msg_str = "일반[Normal]상태입니다. ";
    return_value = "F";
  }
  if (rowState == "D") {
    msg_str = "현재 삭제[Delete]상태입니다. ";
    return_value = "F";
  }
  if (rowState == "U") {
    msg_str = "현재 수정[Update]상태입니다. ";
    return_value = "F";
  }
  if (return_value == "F") {
    await $c.gus.cfAlertMsg($p, row_value + 1 + " 번줄은 " + msg_str + msg_str_tail);
    return return_value;
  } else {
    return return_value;
  }
};

//-------------------------------------------------------------------------
// 단축코드( 장비코드, 작업지시번호)의  중복입력을 체크하는 함수 ; 리턴값-->  F = 실행중지, T = 진행가능
//-------------------------------------------------------------------------
scwin.f_doubleChk = function (eqCd, wrkIndictNo) {
  var rowState = "R";
  var total_cnt = ds_CooperationCompanyInputHeavyEquip.getRowCount();
  for (var i = 0; i < total_cnt; i++) {
    rowState = ds_CooperationCompanyInputHeavyEquip.getRowStatus(i);
    if (rowState == "D") continue; // 해당 Row 가 삭제상태일 경우 무시함.
    if (ds_CooperationCompanyInputHeavyEquip.getCellData(i, "eqCd") == eqCd && ds_CooperationCompanyInputHeavyEquip.getCellData(i, "wrkIndictNo") == wrkIndictNo) {
      return "F";
    }
  }
  return "T";
};

