scwin.f_Save = async function (eqCd) {
  if (ds_CooperationCompanyInputHeavyEquip.getRowCount() == 0) {
    return;
  }
  // alert("저장 데이타셋="+ds_CooperationCompanyInputHeavyEquip.text);
  for (var i = 0; i < ds_CooperationCompanyInputHeavyEquip.getRowCount(); i++) {
    if (ds_CooperationCompanyInputHeavyEquip.getCellData(i, "eqCd") == "" || ds_CooperationCompanyInputHeavyEquip.getCellData(i, "wrkIndictNo") == "" || ds_CooperationCompanyInputHeavyEquip.getCellData(i, "vehclShortCd") == "") {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["단축번호"]);
      return;
    }
  }
  if (await $c.win.confirm($p, MSG_CM_CRM_001)) {
    $c.sbm.execute($p, sbm_SaveInputHeavyEquip);
  }
};

